# GLSL shader for self-displacement with curl noise
shader = '''
out vec4 fragColor;
uniform float uDisplaceAmt;
uniform float uTime;

vec2 curl(vec2 p) {
    float eps = 0.01;
    float n1 = sin(p.x * 10.0 + uTime) * cos(p.y * 10.0);
    float a = sin(p.x * 10.0 + uTime) * cos((p.y + eps) * 10.0);
    float b = sin((p.x + eps) * 10.0 + uTime) * cos(p.y * 10.0);
    return vec2(a - n1, -(b - n1)) / eps;
}

void main()
{
    vec2 uv = vUV.st;

    // Self-displacement: use image brightness to modulate
    vec4 selfColor = texture(sTD2DInputs[0], uv);
    float luma = dot(selfColor.rgb, vec3(0.299, 0.587, 0.114));

    // Curl noise displacement modulated by brightness
    vec2 offset = curl(uv * 3.0) * uDisplaceAmt * (0.5 + luma);

    vec4 displaced = texture(sTD2DInputs[0], uv + offset);
    fragColor = TDOutputSwizzle(displaced);
}
'''
op('/project1/glsl_displace_shader').text = shader
